    int countWinningSequences(string s) {
        int MOD = 1e9 + 7;
        int n = s.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 'F') {
                res = (res * 2 + 1) % MOD;
            } else if (s[i] == 'W') {
                res = (res * 2) % MOD;
            } else {
                res = (res * 2 + 1) % MOD;
            }
        }
        return res;
    }
};```
